<?php if (!empty($case)): ?><section class="section"><div class="container"><h1><?= h($case['title']) ?></h1><div class="case-meta"><span class="badge status-<?= h($case['status'] ?? 'unknown') ?>"><?= h(ucfirst($case['status'] ?? 'Unknown')) ?></span><?php if (!empty($case['filed_date'])): ?><span>Filed <?= h(format_date($case['filed_date'])) ?></span><?php endif; ?></div><?php if (!empty($case['summary'])): ?><p><?= h($case['summary']) ?></p><?php endif; ?></div></section><?php endif; ?>
